              >
                <span className=\"nav-item__icon\">{item.icon}</span>
                {!effectiveCollapsed && <span className=\"nav-item__label\">{item.label}</span>}
                {showBadge && <NotificationBadge text={`${unreadCount}`} tooltipLabel={`${unreadCount} unread notifications`}/>}
