            const isActive = currentView === item.view;
            const Btn = (
              <button
                type=\"button\"
                className={`nav-item ${isActive ? 'nav-item--active' : ''} ${effectiveCollapsed ? 'nav-item--compact' : ''} nav-accent-${item.accent ?? 'gray'}`}
